<?php
 namespace WPAICG\Images\Providers\Google; use WP_Error; use WPAICG\AIPKit_Providers; if (!defined('ABSPATH')) { exit; } class GoogleImageUrlBuilder { public static function build(string $model_id, array $api_params): string|WP_Error { $base_url = !empty($api_params['base_url']) ? rtrim($api_params['base_url'], '/') : 'https://generativelanguage.googleapis.com'; $api_version = !empty($api_params['api_version']) ? $api_params['api_version'] : 'v1beta'; $api_key = !empty($api_params['api_key']) ? $api_params['api_key'] : ''; if (empty($api_key)) { return new WP_Error('missing_google_api_key_for_image_url', __('Google API key is required for image URL construction.', 'gpt3-ai-content-generator')); } $is_video_model = false; if (class_exists('\\WPAICG\\AIPKit_Providers')) { $video_models = AIPKit_Providers::get_google_video_models(); if (is_array($video_models) && !empty($video_models)) { foreach ($video_models as $vm) { $vid = is_array($vm) ? ($vm['id'] ?? '') : (is_string($vm) ? $vm : ''); if (!empty($vid) && $vid === $model_id) { $is_video_model = true; break; } } } } if (!$is_video_model && strpos($model_id, 'veo') !== false) { $is_video_model = true; } if ($is_video_model) { return new WP_Error('video_model_in_image_url_builder', sprintf(__('Video model %s should use GoogleVideoUrlBuilder instead.', 'gpt3-ai-content-generator'), $model_id)); } $model_id_lc = strtolower($model_id); if (strpos($model_id_lc, 'gemini') !== false) { $endpoint_suffix = ':generateContent'; } elseif (strpos($model_id_lc, 'imagen') !== false) { $endpoint_suffix = ':predict'; } else { return new WP_Error('unsupported_google_image_model_for_url', sprintf(__('Unsupported Google image model for URL building: %s', 'gpt3-ai-content-generator'), $model_id)); } $full_path = '/' . trim($api_version, '/') . '/models/' . urlencode($model_id) . $endpoint_suffix; $url_with_key = $base_url . $full_path . '?key=' . urlencode($api_key); return $url_with_key; } } 